"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";

type SelectedRole = "user" | "admin" | null;

export default function LoginPage() {
  const router = useRouter();
  const { loginAsUser, loginAsAdmin } = useAuth();

  const [selectedRole, setSelectedRole] = useState<SelectedRole>(null);
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const handleSelectRole = (role: SelectedRole) => {
    setSelectedRole(role);
    setUsername("");
    setPassword("");
    setError("");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    if (!selectedRole) {
      setError("Please select Guest User or Admin first.");
      return;
    }

    // Dummy credentials
    const userOk =
      selectedRole === "user" &&
      username === "guest@aurora.test" &&
      password === "Guest@123";

    const adminOk =
      selectedRole === "admin" &&
      username === "admin@aurora.test" &&
      password === "Admin@123";

    if (!userOk && !adminOk) {
      setError("Invalid username or password for the selected role.");
      return;
    }

    if (selectedRole === "user") {
      loginAsUser();
      router.push("/");
    } else {
      loginAsAdmin();
      router.push("/orders");
    }
  };

  return (
    <section className="section-wrapper" style={{ backgroundColor: "var(--color-bg)" }}>
      <div className="section-container" style={{ maxWidth: "520px" }}>
        <div style={{ textAlign: "center", marginBottom: "40px" }}>
          <span className="section-label">Access</span>
          <h1 className="section-heading" style={{ marginBottom: "16px" }}>
            Sign In
          </h1>
          <p style={{ fontSize: "14px", color: "var(--color-muted)" }}>
            Choose how you would like to continue. Only admins can access the Orders dashboard.
          </p>
        </div>

        <div
          className="surface"
          style={{
            borderRadius: "12px",
            padding: "28px 24px",
            display: "grid",
            gridTemplateColumns: "1fr",
            gap: "16px",
          }}
        >
          <button
            type="button"
            onClick={() => handleSelectRole("user")}
            className="btn-outline"
            style={{
              width: "100%",
              borderColor:
                selectedRole === "user"
                  ? "var(--color-gold)"
                  : "rgba(201,169,110,0.5)",
            }}
          >
            Continue as Guest User
          </button>

          <button
            type="button"
            onClick={() => handleSelectRole("admin")}
            className="btn-gold"
            style={{
              width: "100%",
              opacity: selectedRole === "admin" ? 1 : 0.9,
            }}
          >
            Continue as Admin
          </button>
        </div>

        {/* Credentials form – only visible after a role is selected */}
        {selectedRole && (
          <form
            onSubmit={handleSubmit}
            style={{
              marginTop: "24px",
              borderRadius: "12px",
              padding: "24px 20px",
              border: "1px solid rgba(201,169,110,0.18)",
              background: "rgba(17,17,17,0.8)",
              display: "grid",
              gap: "14px",
            }}
          >
            <p style={{ fontSize: "13px", color: "var(--color-muted)" }}>
              {selectedRole === "user"
                ? "Enter guest credentials to continue."
                : "Enter admin credentials to access Orders."}
            </p>

            <div style={{ display: "grid", gap: "8px" }}>
              <label
                htmlFor="login-username"
                style={{
                  fontSize: "11px",
                  letterSpacing: "0.15em",
                  textTransform: "uppercase",
                  color: "var(--color-muted)",
                }}
              >
                Username
              </label>
              <input
                id="login-username"
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder={
                  selectedRole === "user"
                    ? "guest@aurora.test"
                    : "admin@aurora.test"
                }
                style={{
                  width: "100%",
                  padding: "10px 12px",
                  borderRadius: "6px",
                  border: "1px solid rgba(201,169,110,0.25)",
                  background: "transparent",
                  color: "var(--color-text)",
                  fontSize: "14px",
                }}
              />
            </div>

            <div style={{ display: "grid", gap: "8px" }}>
              <label
                htmlFor="login-password"
                style={{
                  fontSize: "11px",
                  letterSpacing: "0.15em",
                  textTransform: "uppercase",
                  color: "var(--color-muted)",
                }}
              >
                Password
              </label>
              <input
                id="login-password"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder={
                  selectedRole === "user" ? "Guest@123" : "Admin@123"
                }
                style={{
                  width: "100%",
                  padding: "10px 12px",
                  borderRadius: "6px",
                  border: "1px solid rgba(201,169,110,0.25)",
                  background: "transparent",
                  color: "var(--color-text)",
                  fontSize: "14px",
                }}
              />
            </div>

            {error && (
              <p style={{ fontSize: "12px", color: "#f97373", marginTop: "4px" }}>
                {error}
              </p>
            )}

            <button
              type="submit"
              className="btn-gold"
              style={{ width: "100%", marginTop: "4px" }}
            >
              Sign In
            </button>
          </form>
        )}

        <p
          style={{
            marginTop: "16px",
            fontSize: "12px",
            color: "var(--color-muted)",
            textAlign: "center",
          }}
        >
          Dummy credentials — Guest: <strong>guest@aurora.test / Guest@123</strong>{" "}
          • Admin: <strong>admin@aurora.test / Admin@123</strong>
        </p>
      </div>
    </section>
  );
}


